from subprocess import call

def install(package):
    call(['pip', 'install', package, '--upgrade'])

with open('requirements.txt') as f:
    requirements = f.read().splitlines()

for requirement in requirements:
    if not requirement.startswith('#'):  # skip comments
        install(requirement)